   665→        })
   666→        .where(
   667→          and(
   668→            eq(manhourCapacity.depotId, request.depotId),
   669→            lte(manhourCapacity.effectiveFrom, effectiveFromStr),
   670→            or(isNull(manhourCapacity.effectiveTo), gte(manhourCapacity.effectiveTo, effectiveFromStr))
   671→          )
   672→        );
   673→
