  1271→  /**
  1272→   * Find PMs that can be shifted to another week
  1273→   */
  1274→  private async findShiftablePMs(
  1275→    fromWeek: ProjectionData,
  1276→    toWeek: ProjectionData,
  1277→    targetHours: number,
  1278→    strategy: 'ADVANCE_PM' | 'DEFER_PM'
  1279→  ): Promise<ShiftablePM[]> {
  1280→    const fromStart = format(fromWeek.week, 'yyyy-MM-dd');
  1281→    const fromEnd = format(addDays(fromWeek.week, 6), 'yyyy-MM-dd');
  1282→
  1283→    // Get PMs in the overloaded week
  1284→    const scheduledPMs = await this.db
  1285→      .select({
  1286→        id: pmSchedule.id,
  1287→        trainId: pmSchedule.trainId,
  1288→        pmTypeId: pmSchedule.pmTypeId,
  1289→        targetDate: pmSchedule.targetDate,
  1290→        constraintStart: pmSchedule.constraintStart,
  1291→        constraintEnd: pmSchedule.constraintEnd,
  1292→        isLocked: pmSchedule.isLocked,
  1293→      })
  1294→      .from(pmSchedule)
  1295→      .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
  1296→      .where(
  1297→        and(
  1298→          eq(trains.currentDepotId, fromWeek.depotId),
  1299→          gte(pmSchedule.targetDate, fromStart),
  1300→          lte(pmSchedule.targetDate, fromEnd),
  1301→          inArray(pmSchedule.status, ['SCHEDULED']), // Not CONFIRMED, IN_PROGRESS, or COMPLETED
  1302→          eq(pmSchedule.isLocked, false), // Not locked
  1303→          isNull(pmSchedule.scenarioId) // Real schedule
  1304→        )
  1305→      );
  1306→
  1307→    if (scheduledPMs.length === 0) {
  1308→      return [];
  1309→    }
  1310→
  1311→    // Get PM type info
  1312→    const pmTypeIds = [...new Set(scheduledPMs.map((p) => p.pmTypeId))];
  1313→    const pmTypeInfo = await this.db.query.pmTypes.findMany({
  1314→      where: inArray(pmTypes.id, pmTypeIds),
  1315→      columns: { id: true, pmCode: true, estimatedHours: true },
  1316→    });
  1317→    const typeMap = new Map(pmTypeInfo.map((pt) => [pt.id, pt]));
  1318→
  1319→    // Filter PMs that can be shifted to target week
  1320→    const shiftablePMs: ShiftablePM[] = [];
  1321→    let accumulatedHours = 0;
  1322→
  1323→    for (const pm of scheduledPMs) {
  1324→      if (accumulatedHours >= targetHours) break;
  1325→
  1326→      const pmType = typeMap.get(pm.pmTypeId);
  1327→      if (!pmType) continue;
  1328→
  1329→      const constraintStart = pm.constraintStart ? parseISO(pm.constraintStart) : null;
  1330→      const constraintEnd = pm.constraintEnd ? parseISO(pm.constraintEnd) : null;
  1331→
  1332→      // Check if target week is within compliance window
  1333→      const targetDate = strategy === 'ADVANCE_PM' ? toWeek.week : addDays(toWeek.week, 6);
  1334→
  1335→      const withinWindow =
  1336→        (!constraintStart || !isBefore(targetDate, constraintStart)) &&
  1337→        (!constraintEnd || !isAfter(targetDate, constraintEnd));
  1338→
  1339→      if (withinWindow) {
  1340→        const hours = parseFloat(pmType.estimatedHours ?? '0');
  1341→        shiftablePMs.push({
  1342→          id: pm.id,
  1343→          trainId: pm.trainId,
  1344→          pmTypeCode: pmType.pmCode,
  1345→          estimatedHours: hours,
  1346→          currentDate: parseISO(pm.targetDate),
  1347→          constraintStart: constraintStart ?? new Date(0),
  1348→          constraintEnd: constraintEnd ?? new Date(9999, 11, 31),
  1349→        });
  1350→        accumulatedHours += hours;
  1351→      }
  1352→    }
  1353→
  1354→    return shiftablePMs;
  1355→  }
  1356→
  1357→  /**
  1358→   * Find other depots with available capacity
  1359→   */
  1360→  private async findDepotsWithCapacity(
  1361→    week: Date,
  1362→    minHours: number,
  1363→    excludeDepotId: string
  1364→  ): Promise<DepotWithCapacity[]> {
  1365→    // Get all depots except the excluded one
  1366→    const otherDepots = await this.db.query.depots.findMany({
  1367→      where: sql`${depots.id} != ${excludeDepotId}`,
  1368→    });
  1369→
  1370→    const results: DepotWithCapacity[] = [];
  1371→
  1372→    for (const depot of otherDepots) {
  1373→      const capacity = await this.getCapacity(depot.id, week);
  1374→      if (!capacity) continue;
  1375→
  1376→      // Get PM hours for this depot/week
  1377→      const pmHours = await this.getPmHoursForPeriod(depot.id, week, addDays(week, 6));
  1378→
  1379→      // Calculate available capacity
  1380→      const weeklyCapacity = this.calculateWeeklyCapacity(capacity);
  1381→      const availableHours = weeklyCapacity.regular + weeklyCapacity.overtime - pmHours;
  1382→
  1383→      if (availableHours >= minHours) {
  1384→        results.push({
  1385→          depotId: depot.id,
  1386→          depotCode: depot.code,
  1387→          depotName: depot.name,
  1388→          availableHours: Math.min(availableHours, minHours),
  1389→        });
  1390→      }
  1391→    }
  1392→
  1393→    // Sort by available hours (descending)
  1394→    return results.sort((a, b) => b.availableHours - a.availableHours);
  1395→  }
  1396→
  1397→  /**
  1398→   * Get base labor rate for a depot
  1399→   */
  1400→  private async getBaseRate(depotId?: string): Promise<number> {
  1401→    if (!depotId) {
  1402→      return DEFAULT_BASE_RATE;
  1403→    }
  1404→
  1405→    const rate = await this.db.query.laborRates.findFirst({
  1406→      where: and(
  1407→        eq(laborRates.depotId, depotId),
  1408→        lte(laborRates.effectiveFrom, format(new Date(), 'yyyy-MM-dd')),
  1409→        or(isNull(laborRates.effectiveTo), gte(laborRates.effectiveTo, format(new Date(), 'yyyy-MM-dd')))
  1410→      ),
  1411→      orderBy: [desc(laborRates.effectiveFrom)],
  1412→    });
  1413→
  1414→    return rate ? parseFloat(rate.regularHourlyRate ?? String(DEFAULT_BASE_RATE)) : DEFAULT_BASE_RATE;
  1415→  }
  1416→
  1417→  // ===========================================================================
  1418→  // Private: Apply Adjustments & Calculate Metrics
  1419→  // ===========================================================================
  1420→
  1421→  /**
  1422→   * Apply adjustments to projections (simulation, not persisted)
  1423→   */
  1424→  private applyAdjustments(
  1425→    projections: ProjectionData[],
  1426→    adjustments: ProposedAdjustment[]
  1427→  ): ProjectionData[] {
  1428→    // Create deep copy
  1429→    const leveled = projections.map((p) => ({
  1430→      ...p,
  1431→      required: { ...p.required },
  1432→      available: { ...p.available },
  1433→    }));
  1434→
  1435→    // Build lookup by week
  1436→    const weekMap = new Map(leveled.map((p) => [p.week.toISOString(), p]));
  1437→
  1438→    for (const adj of adjustments) {
  1439→      if (adj.type === 'MANUAL_REVIEW') continue;
  1440→
  1441→      const sourceKey = adj.sourcePeriod.start.toISOString();
  1442→      const source = weekMap.get(sourceKey);
  1443→
  1444→      if (adj.type === 'ADVANCE_PM' || adj.type === 'DEFER_PM') {
  1445→        // Move hours from source to target
  1446→        if (source && adj.targetPeriod) {
  1447→          const targetKey = adj.targetPeriod.start.toISOString();
  1448→          const target = weekMap.get(targetKey);
  1449→
  1450→          if (target) {
  1451→            source.required.pm -= adj.hoursAdjusted;
  1452→            source.required.total -= adj.hoursAdjusted;
  1453→            target.required.pm += adj.hoursAdjusted;
  1454→            target.required.total += adj.hoursAdjusted;
  1455→          }
  1456→        }
  1457→      } else if (adj.type === 'ADD_OVERTIME') {
  1458→        // Increase available hours in source
  1459→        if (source) {
  1460→          // Overtime is already counted in available.total
  1461→          // No change needed to projected available hours
  1462→        }
  1463→      } else if (adj.type === 'CROSS_DEPOT' || adj.type === 'ADD_CONTRACTOR') {
  1464→        // Reduce required hours in source (work transferred out)
  1465→        if (source) {
  1466→          source.required.total -= adj.hoursAdjusted;
  1467→        }
  1468→      }
  1469→    }
  1470→
  1471→    // Recalculate metrics for all weeks
  1472→    for (const p of leveled) {
  1473→      p.variance = p.available.total - p.required.total;
  1474→      p.utilizationPct = p.available.total > 0 ? p.required.total / p.available.total : 0;
  1475→      p.isOverloaded = p.utilizationPct > MAX_UTILIZATION;
  1476→      p.isUnderutilized = p.utilizationPct < MIN_UTILIZATION;
  1477→    }
  1478→
  1479→    return leveled;
  1480→  }
  1481→
  1482→  /**
  1483→   * Calculate aggregate metrics
  1484→   */
  1485→  private calculateMetrics(projections: ProjectionData[]): LevelingMetrics {
  1486→    if (projections.length === 0) {
  1487→      return {
  1488→        avgUtilization: 0,
  1489→        minUtilization: 0,
  1490→        maxUtilization: 0,
  1491→        overloadedWeeks: 0,
  1492→        underutilizedWeeks: 0,
  1493→        totalRequiredHours: 0,
  1494→        totalAvailableHours: 0,
  1495→      };
  1496→    }
  1497→
  1498→    const utilizations = projections.map((p) => p.utilizationPct);
  1499→
  1500→    return {
  1501→      avgUtilization: utilizations.reduce((a, b) => a + b, 0) / utilizations.length,
  1502→      minUtilization: Math.min(...utilizations),
  1503→      maxUtilization: Math.max(...utilizations),
  1504→      overloadedWeeks: projections.filter((p) => p.isOverloaded).length,
  1505→      underutilizedWeeks: projections.filter((p) => p.isUnderutilized).length,
  1506→      totalRequiredHours: projections.reduce((sum, p) => sum + p.required.total, 0),
  1507→      totalAvailableHours: projections.reduce((sum, p) => sum + p.available.total, 0),
  1508→    };
  1509→  }
  1510→
  1511→  /**
  1512→   * Group projections by depot
  1513→   */
  1514→  private groupByDepot(projections: ProjectionData[]): Map<string, ProjectionData[]> {
  1515→    const result = new Map<string, ProjectionData[]>();
  1516→
  1517→    for (const p of projections) {
  1518→      const existing = result.get(p.depotId) ?? [];
  1519→      existing.push(p);
  1520→      result.set(p.depotId, existing);
  1521→    }
  1522→
  1523→    return result;
  1524→  }
  1525→
  1526→  // ===========================================================================
  1527→  // Private: Persistence
  1528→  // ===========================================================================
  1529→
  1530→  /**
  1531→   * Persist projections and adjustments to database
  1532→   */
  1533→  private async persistProjections(
  1534→    runId: string,
  1535→    projections: ProjectionData[],
  1536→    adjustments: ProposedAdjustment[]
  1537→  ): Promise<void> {
  1538→    await this.inTransaction('persistProjections', async (tx, span) => {
  1539→      span.setAttribute('projectionRunId', runId);
  1540→      span.setAttribute('projectionCount', projections.length);
  1541→      span.setAttribute('adjustmentCount', adjustments.length);
  1542→
  1543→      // Insert projections
  1544→      for (const p of projections) {
  1545→        const [inserted] = await tx
  1546→          .insert(manhourProjections)
  1547→          .values({
  1548→            projectionRunId: runId,
  1549→            depotId: p.depotId,
  1550→            periodStart: format(p.week, 'yyyy-MM-dd'),
  1551→            periodEnd: format(addDays(p.week, 6), 'yyyy-MM-dd'),
  1552→            granularity: p.granularity,
  1553→            requiredPmHours: String(p.required.pm),
  1554→            requiredCorrectiveHours: String(p.required.corrective),
  1555→            requiredOverhaulHours: String(p.required.overhaul),
  1556→            requiredTotalHours: String(p.required.total),
  1557→            availableRegularHours: String(p.available.regular),
  1558→            availableOvertimeHours: String(p.available.overtime),
  1559→            availableTotalHours: String(p.available.total),
  1560→          })
  1561→          .returning();
  1562→
  1563→        // Insert adjustments for this projection
  1564→        const projectionAdjustments = adjustments.filter(
  1565→          (a) =>
  1566→            a.sourcePeriod.start.toISOString() === p.week.toISOString() &&
  1567→            (!p.depotCode || a.sourcePeriod.start.toISOString() === p.week.toISOString())
  1568→        );
  1569→
  1570→        for (const adj of projectionAdjustments) {
  1571→          await tx.insert(manhourAdjustments).values({
  1572→            projectionId: inserted.id,
  1573→            adjustmentType: adj.type,
  1574→            sourcePeriodStart: format(adj.sourcePeriod.start, 'yyyy-MM-dd'),
  1575→            sourcePeriodEnd: format(adj.sourcePeriod.end, 'yyyy-MM-dd'),
  1576→            targetPeriodStart: adj.targetPeriod
  1577→              ? format(adj.targetPeriod.start, 'yyyy-MM-dd')
  1578→              : null,
  1579→            targetPeriodEnd: adj.targetPeriod ? format(adj.targetPeriod.end, 'yyyy-MM-dd') : null,
  1580→            hoursAdjusted: String(adj.hoursAdjusted),
  1581→            affectedPmIds: adj.affectedPMs,
  1582→            affectedTrainIds: adj.affectedTrains,
  1583→            costImpact: String(adj.costImpact),
  1584→            riskImpact: adj.riskLevel,
  1585→            reason: adj.reason,
  1586→            status: 'PROPOSED',
  1587→          });
  1588→        }
  1589→      }
  1590→    });
  1591→  }
  1592→}
