   792→      span.setAttribute('track.id', trackId);
   793→      span.setAttribute('pm.targetDate', targetDate);
   794→
   795→      const endDate = new Date(targetDate);
   796→      endDate.setDate(endDate.getDate() + durationDays - 1);
   797→      const endDateStr = endDate.toISOString().split('T')[0];
   798→
   799→      const conditions: SQL<unknown>[] = [
   800→        eq(pmSchedule.assignedTrackId, trackId),
   801→        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
   802→        isNull(pmSchedule.scenarioId),
