  2167→    const trackConditions: SQL<unknown>[] = [
  2168→      eq(tracks.active, true),
  2169→      sql`${tracks.trackType} != 'STABLING'`,
  2170→    ];
  2171→
  2172→    if (depotId) {
  2173→      trackConditions.push(eq(tracks.depotId, depotId));
  2174→    }
  2175→
  2176→    const trackCount = await this.db
  2177→      .select({ count: count() })
  2178→      .from(tracks)
  2179→      .where(and(...trackConditions));
